import{_ as e,c as t,o,a4 as n}from"./chunks/framework.BmdFiWrL.js";const g=JSON.parse('{"title":"Getting Started","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"en_US/developer/getting-started.md","filePath":"en_US/developer/getting-started.md","lastUpdated":1780261573000}'),a={name:"en_US/developer/getting-started.md"},i=n(`<h1 id="getting-started" tabindex="-1">Getting Started <a class="header-anchor" href="#getting-started" aria-label="Permalink to &quot;Getting Started&quot;">​</a></h1><p>This guide walks you through setting up a development environment so you can quickly start contributing to Nezha.</p><p>First, fork the Nezha repository so you have a place to save your changes. You can then choose container-based development or local development. To help you get started faster, this guide introduces container-based development first.</p><h2 id="container-development-environment" tabindex="-1">Container Development Environment <a class="header-anchor" href="#container-development-environment" aria-label="Permalink to &quot;Container Development Environment&quot;">​</a></h2><p>To use container-based development in VS Code, install the <code>ms-vscode-remote.remote-containers</code> extension.</p><h3 id="github-codespaces" tabindex="-1">GitHub Codespaces <a class="header-anchor" href="#github-codespaces" aria-label="Permalink to &quot;GitHub Codespaces&quot;">​</a></h3><p>In your forked repository, click <code>Code</code> -&gt; <code>Codespaces</code> -&gt; <code>Create codespace on master</code> in the upper-right corner to create a cloud development environment, then wait for the environment to finish building.</p><p>You can also install the <code>GitHub.codespaces</code> extension in VS Code or another supported IDE and connect directly from there.</p><h3 id="remote-container-development" tabindex="-1">Remote Container Development <a class="header-anchor" href="#remote-container-development" aria-label="Permalink to &quot;Remote Container Development&quot;">​</a></h3><p>If you have a dedicated development server with Docker or a compatible runtime installed, you can create and build a remote development container over SSH and develop on that remote server. The following example uses VS Code:</p><ol><li><p>Configure your <code>~/.ssh/config</code> file on *nix or <code>%HOMEPATH%/.ssh/config</code> on Windows. Here is a simple example:</p><div class="language-ssh-config vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ssh-config</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">Host</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> Dev</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  HostName</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> dev.server.host</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  User</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &lt;your-username&gt;</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  IdentityFile</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> &lt;path-to-your-private-key&gt;</span></span></code></pre></div></li><li><p>Log in to the remote server with SSH. If the first step is configured correctly, you can test it with <code>ssh Dev</code>.</p></li><li><p>Clone your forked repository on the server: <code>git clone &lt;your-forked-repository-url&gt;</code>.</p></li><li><p>Open the VS Code Remote Explorer from the left sidebar. You need to install the official <code>remote</code> extension series.</p></li><li><p>Open the cloned directory in VS Code.</p></li><li><p>Press <code>F1</code>, then type and select <code>Dev Containers: Rebuild and Reopen in Container</code>.</p></li><li><p>Wait for the development environment to finish building.</p></li></ol><h3 id="local-container-development" tabindex="-1">Local Container Development <a class="header-anchor" href="#local-container-development" aria-label="Permalink to &quot;Local Container Development&quot;">​</a></h3><p>If Docker or a compatible runtime is installed on your local machine, you can create and build the development container locally. You may encounter network issues depending on your environment; resolve them according to your local network setup. The following example uses VS Code:</p><ol><li><p>Clone the repository:</p><div class="language-shell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">shell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">your-forked-repository-ur</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">l</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre></div></li><li><p>Open the cloned directory in VS Code.</p></li><li><p>Press <code>F1</code>, then type and select <code>Dev Containers: Rebuild and Reopen in Container</code>.</p></li><li><p>Wait for the development environment to finish building.</p></li></ol><h2 id="start-developing" tabindex="-1">Start Developing <a class="header-anchor" href="#start-developing" aria-label="Permalink to &quot;Start Developing&quot;">​</a></h2><p>After the environment finishes its automatic setup, Nezha is ready to build by default. You can start editing freely and run <code>.devcontainer/build.sh</code> to compile and test your changes.</p><h3 id="read-the-documentation" tabindex="-1">Read the Documentation <a class="header-anchor" href="#read-the-documentation" aria-label="Permalink to &quot;Read the Documentation&quot;">​</a></h3><p>You can read the <a href="./api.html">API documentation</a> to learn which Web APIs Nezha provides.</p><p>If you use one of the container development environments above, these files have already been generated and are stored under <code>cmd/dashboard/docs</code> in the development environment.</p>`,19),s=[i];function r(l,d,p,c,h,u){return o(),t("div",null,s)}const v=e(a,[["render",r]]);export{g as __pageData,v as default};
